//---------------------------------------------------------
//нҷ”л©ҙм„ёнҢ…
//---------------------------------------------------------
scwin.f_Set = function (gubun) {
  switch (gubun) {
    case "INIT":
      // мҙҲкё°нҷ”
      $c.gus.cfDisableKeyData($p);
      $c.gus.cfDisableBtnOnly($p, [btn_Print, btn_Create, btn_Update, btn_Cancel, btn_Save, btn_Delete]);
      $c.gus.cfEnableBtnOnly($p, [btn_Create]);
      $c.gus.cfDisableObjects($p, [cnd_lc_seaair, cnd_lc_iogb]);
      scwin.f_DisablePopUpObj();
      break;
    case "RETRIEVE":
      // мЎ°нҡҢлӘЁл“ң
      $c.gus.cfDisableKeyData($p);
      scwin.f_DisablePopUpObj();
      if (scwin.processFlag === "RETRIEVE") {
        $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Cancel]);
        $c.gus.cfEnableBtnOnly($p, [btn_Create, btn_Update, btn_Delete, btn_Print]);
      } else {
        $c.gus.cfDisableBtnOnly($p, [btn_Cancel, btn_Update, btn_Save, btn_Delete, btn_Print]);
        $c.gus.cfEnableBtnOnly($p, [btn_Create]);
      }
      break;
    case "CANCEL":
      // м·ЁмҶҢ
      scwin.f_Set("RETRIEVE");
      break;
    case "CREATE":
      // мӢ к·ң
      $c.gus.cfEnableKeyData($p);
      scwin.f_EnablePopUpObj();
      $c.gus.cfDisableBtnOnly($p, [btn_Create, btn_Update, btn_Delete]);
      $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Cancel]);

      //            $c.gus.cfEnableObj(cnd_lc_iogb, true); // House

      $c.gus.cfEnableObj($p, ed_ccano, false); // CCA No
      $c.gus.cfEnableObj($p, ed_mblno, false); // Master
      $c.gus.cfEnableObj($p, lc_mmhno, false); // Master Consol

      $c.gus.cfEnableObj($p, ed_blno, true); // House
      $c.gus.cfEnableObj($p, lc_hmhno, true); // House Consol
      break;
    case "UPDATE":
      $c.gus.cfEnableKeyData($p);
      scwin.f_EnablePopUpObj();
      $c.gus.cfDisableBtnOnly($p, [btn_Create, btn_Update, btn_Delete, btn_Print]);
      $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Cancel]);
      $c.gus.cfEnableObj($p, ed_ccano, false); // CCA No
      $c.gus.cfEnableObj($p, ed_mblno, false); // Master
      $c.gus.cfEnableObj($p, lc_mmhno, false); // Master Consol

      $c.gus.cfEnableObj($p, ed_blno, true); // House
      $c.gus.cfEnableObj($p, lc_hmhno, true); // House Consol
      break;
    case "SAVE":
      $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Cancel]);
      $c.gus.cfEnableBtnOnly($p, [btn_Update, btn_Create, btn_Delete]);
      scwin.f_Set("RETRIEVE");
      break;
    case "DELETE":
      $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Cancel]);
      $c.gus.cfEnableBtnOnly($p, [btn_Create, btn_Update, btn_Delete]);
      scwin.f_Set("RETRIEVE");
      break;
  }
};

