scwin.f_Delete = async function () {
  let chk = await $c.win.confirm($p, E_MSG_CM_CRM_004); // мӮӯм ңн•ҳмӢңкІ мҠөлӢҲк№Ң?
  if (chk) {
    let intRowPosition = ds_correctionNotice.getRowPosition();
    ds_correctionNotice.deleteRow(intRowPosition);
    scwin.processFlag = "RETRIEVE"; // вҶҗ м¶”к°Җ (мӮӯм ң нӣ„ мЎ°нҡҢ)
    await $c.sbm.execute($p, sbm_save);
  }
};

