scwin.f_Chk = function (disGubun) {
  // getValue() >> 1: checked , 0: unchecked
  switch (disGubun) {
    case 1:
      // G/Weight
      if (chb_chkGwht.getValue() === "1") {
        scwin.cfViewTab(0);
        if (ds_bl.getRowCount() > 0) {
          txa_mark1.setValue(txa_mark1.getValue() + "GROSS W/T : " + ds_bl.getCellData(0, "gwgt") + "\r\n");
          txa_mark2.setValue(txa_mark2.getValue() + "GROSS W/T : " + "\r\n");
        }
      }
      break;
    case 2:
      //Chargeable Weight / Rate
      if (chb_chkCwht.getValue() === "1" || chb_chkRate.getValue() === "1") {
        if (ds_blFreight.getRowCount() > 0 && ds_correctionNoticeFreightList.getRowCount() < 1) {
          scwin.cfViewTab(1);
          for (let i = 0; i < ds_blFreight.getRowCount(); i++) {
            ds_correctionNoticeFreightList.insertRow();
            ds_correctionNoticeFreightList.setCellData(i, "kcomcd", ds_blFreight.getCellData(i, "kcomcd"));
            ds_correctionNoticeFreightList.setCellData(i, "ccano", ds_blFreight.getCellData(i, "ccano"));
            ds_correctionNoticeFreightList.setCellData(i, "icgb", "C");
            ds_correctionNoticeFreightList.setCellData(i, "fcode", ds_blFreight.getCellData(i, "fcode"));
            ds_correctionNoticeFreightList.setCellData(i, "fdesc", ds_blFreight.getCellData(i, "fdesc"));
            ds_correctionNoticeFreightList.setCellData(i, "pcgb", ds_blFreight.getCellData(i, "pcgb"));
            ds_correctionNoticeFreightList.setCellData(i, "cwht", ds_blFreight.getCellData(i, "cwht"));
            ds_correctionNoticeFreightList.setCellData(i, "rate", ds_blFreight.getCellData(i, "rate"));
            ds_correctionNoticeFreightList.setCellData(i, "charge", ds_blFreight.getCellData(i, "charge"));
            ds_inCorrectionNoticeFreightList.insertRow();
            ds_inCorrectionNoticeFreightList.setCellData(i, "kcomcd", ds_blFreight.getCellData(i, "kcomcd"));
            ds_inCorrectionNoticeFreightList.setCellData(i, "ccano", ds_blFreight.getCellData(i, "ccano"));
            ds_inCorrectionNoticeFreightList.setCellData(i, "icgb", ds_blFreight.getCellData(i, "icgb"));
            ds_inCorrectionNoticeFreightList.setCellData(i, "fcode", ds_blFreight.getCellData(i, "fcode"));
            ds_inCorrectionNoticeFreightList.setCellData(i, "fdesc", ds_blFreight.getCellData(i, "fdesc"));
            ds_inCorrectionNoticeFreightList.setCellData(i, "pcgb", ds_blFreight.getCellData(i, "pcgb"));
            ds_inCorrectionNoticeFreightList.setCellData(i, "cwht", ds_blFreight.getCellData(i, "cwht"));
            ds_inCorrectionNoticeFreightList.setCellData(i, "rate", ds_blFreight.getCellData(i, "rate"));
            ds_inCorrectionNoticeFreightList.setCellData(i, "charge", ds_blFreight.getCellData(i, "charge"));
          }
        }
      }
      break;
    case 3:
      //Pieces
      if (chb_chkPcs.getValue() === "1") {
        scwin.cfViewTab(0);
        if (ds_bl.getRowCount() > 0) {
          txa_mark1.setValue(txa_mark1.getValue() + "PIECES : " + ds_bl.getCellData(0, "pkg") + "\r\n");
          txa_mark2.setValue(txa_mark2.getValue() + "PIECES : " + "\r\n");
        }
      }
      break;
    case 4:
      // Consignee
      if (chb_chkCn.getValue() === "1") {
        scwin.cfViewTab(0);
        if (ds_bl.getRowCount() > 0) {
          txa_mark1.setValue(txa_mark1.getValue() + "Consignee : " + "\r\n   " + ds_bl.getCellData(0, "cnnm1") + "\r\n");
          if (ds_bl.getCellData(0, "cnnm2") != "") {
            txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "cnnm2") + "\r\n");
          }
          if (ds_bl.getCellData(0, "cnnm3") != "") {
            txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "cnnm3") + "\r\n");
          }
          if (ds_bl.getCellData(0, "cnnm4") != "") {
            txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "cnnm4") + "\r\n");
          }
          if (ds_bl.getCellData(0, "cnnm5") != "") {
            txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "cnnm5") + "\r\n");
          }
          txa_mark2.setValue(txa_mark2.getValue() + "Consignee : " + "\r\n   ");
        }
      }
      break;
    case 5:
      // Shipper
      if (chb_chkSh.getValue() === "1") {
        scwin.cfViewTab(0);
        if (ds_bl.getRowCount() > 0) {
          txa_mark1.setValue(txa_mark1.getValue() + "Shipper : " + "\r\n   " + ds_bl.getCellData(0, "shnm1") + "\r\n");
          if (ds_bl.getCellData(0, "shnm2") != "") {
            txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "shnm2") + "\r\n");
          }
          if (ds_bl.getCellData(0, "shnm3") != "") {
            txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "shnm3") + "\r\n");
          }
          if (ds_bl.getCellData(0, "shnm4") != "") {
            txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "shnm4") + "\r\n");
          }
          if (ds_bl.getCellData(0, "shnm5") != "") {
            txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "shnm5") + "\r\n");
          }
          txa_mark2.setValue(txa_mark2.getValue() + "Shipper : " + "\r\n   ");
        }
      }
      break;
    case 6:
      //Destination
      if (chb_chkDest.getValue() === "1") {
        scwin.cfViewTab(0);
        if (ds_bl.getRowCount() > 0) {
          ed_idest.setValue(ds_bl.getCellData(0, "dpcd")); // Departure
          ed_idscd1.setValue(ds_bl.getCellData(0, "dscd1")); // TO-1
          ed_iptcd1.setValue(ds_bl.getCellData(0, "ptcd1")); // First Carrier
          ed_idscd2.setValue(ds_bl.getCellData(0, "dscd2")); // To-2
          ed_iptcd2.setValue(ds_bl.getCellData(0, "ptcd2")); // By-1
          ed_idscd3.setValue(ds_bl.getCellData(0, "dscd3")); // To-3
          ed_iptcd3.setValue(ds_bl.getCellData(0, "ptcd3")); // By-2
        }
      }
      break;
    case 7:
      // Notify
      if (chb_chkNt.getValue() === "1") {
        scwin.cfViewTab(0);
        if (ds_bl.getRowCount() > 0) {
          txa_mark1.setValue(txa_mark1.getValue() + "Notify  : " + "\r\n   " + ds_bl.getCellData(0, "ntnm1") + "\r\n");
          if (ds_bl.getCellData(0, "ntnm2") != "") {
            txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "ntnm2") + "\r\n");
          }
          if (ds_bl.getCellData(0, "ntnm3") != "") {
            txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "ntnm3") + "\r\n");
          }
          if (ds_bl.getCellData(0, "ntnm4") != "") {
            txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "ntnm4") + "\r\n");
          }
          if (ds_bl.getCellData(0, "ntnm5") != "") {
            txa_mark1.setValue(txa_mark1.getValue() + "   " + ds_bl.getCellData(0, "ntnm5") + "\r\n");
          }
          txa_mark2.setValue(txa_mark2.getValue() + "Notify  : " + "\r\n   ");
        }
      }
      break;
    default:
      break;
  }
};

