// BL лҚ°мқҙн„° display нҸ¬л§· м Ғмҡ©
scwin.applyFormatBl = function (value) {
  // к°’мқҙ м—Ҷкұ°лӮҳ 3мһҗлҰ¬ мқҙн•ҳмқё кІҪмҡ° к·ёлҢҖлЎң л°ҳнҷҳ
  if (!value || value.length <= 3) {
    return value;
  }
  let returnVal = value.substring(0, 3) + "-" + value.substring(3);
  // м•һ 3мһҗлҰ¬ + "-" + лӮҳлЁём§Җ м „мІҙ
  return returnVal.toUpperCase();
};
scwin.applyUpper = function (value) {
  let returnVal = value.substring(0);
  return returnVal.toUpperCase();
};
scwin.gr_correctFreight_oneditend = function (rowIndex, columnIndex, value) {
  // debugger; 
  let columnId = gr_correctFreight.getColumnID(columnIndex);
  let val = value.toUpperCase();
  if (columnId === "fcode") {
    udc_ilcomCode_Grid.setSelectId("retriveFreightCodeInfo");
    udc_ilcomCode_Grid.ilCommonPopUp(function (rtnList) {
      scwin.callbackGridFreight(rtnList, rowIndex);
    }, val,
    //ds_correctionNoticeFreightList.getCellData(rowIndex, "fcode"),
    ds_correctionNoticeFreightList.getCellData(rowIndex, "fdesc"), 'T', '2', 'Freight Code,Freight Name', '150,170', null, null, '440', '500', null, null, null, "F", 'Freight Search,Freight Code,Freight Name');
  }
};
